111→
112→/**
113→ * Interaction data (mirrors Prisma Interaction model)
114→ */
115→export type InteractionData = Interaction;
116→
117→/**
118→ * Interaction filter options for getInteractions
119→ */
120→export interface InteractionFilters {
121→  contactId?: string;
122→  type?: string;
123→}
124→
125→/**
126→ * Interaction creation input
127→ */
128→export interface InteractionCreateInput {
129→  contactId: string;
130→  type: string;
131→  direction?: string | null;
132→  subject?: string | null;
133→  content?: string | null;
134→  scheduledAt?: string | null;
135→  completedAt?: string | null;
136→  authorId: string;
137→  eventId?: string | null;
138→}
139→
