164→/**
165→ * Deal history data with stage relations
166→ */
167→export interface DealHistoryData {
168→  id: string;
169→  dealId: string;
170→  fromStageId: string | null;
171→  toStageId: string | null;
172→  comment: string | null;
173→  changedBy: string;
174→  changedAt: Date;
