259→  changedBy: string;
260→  comment?: string | null;
261→}
262→
263→/**
264→ * Contract data with relations
265→ */
266→export interface ContractData extends Omit<Contract, 'deletedAt'> {
267→  contact?: ContactData | null;
268→  deal?: DealData | null;
269→  template?: ContractTemplateData | null;
270→  versions?: ContractVersionData[];
271→  signers?: ContractSignerData[];
272→}
273→
