276→ */
277→export interface ContractVersionData extends Omit<ContractVersion, 'contractId'> {}
278→
279→/**
280→ * Contract signer data
281→ */
282→export interface ContractSignerData extends Omit<ContractSigner, 'contractId'> {}
283→
284→/**
285→ * Contract template data
286→ */
287→export interface ContractTemplateData extends Omit<ContractTemplate, 'createdBy'> {}
288→
289→/**
290→ * Contract filter options
291→ */
292→export interface ContractFilters {
293→  status?: string;
294→  contactId?: string;
295→  dealId?: string;
296→}
297→
298→/**
299→ * Contract list params
300→ */
301→export interface ContractListParams extends ContractFilters, PaginationOptions {}
